def in_range(value, bounds):
    return bounds[0] <= value <= bounds[1]


def unique_candidates(candidates):
    cleaned = []
    seen = set()
    for candidate in candidates:
        if candidate is None or not math.isfinite(candidate):
            continue
        key = round(candidate, 10)
        if key in seen:
            continue
        seen.add(key)
        cleaned.append(candidate)
    return cleaned


def score_candidate(feature, value):
    low, high = CONVERSION_RANGES[feature]
    center = CENTERS[feature]
    span = max(high - low, 1e-9)
    distance = abs(value - center) / span
    raw_penalty = 0.0
    if feature in {'Troponin_I', 'Troponin_T'} and value >= 1.0:
        raw_penalty += 0.8
    if feature == 'Lactate' and value >= 10.0:
        raw_penalty += 0.4
    return distance + raw_penalty


def candidates_for_feature(feature, raw):
    candidates = [raw]

    if feature in GENERAL_FACTORS:
        factor = GENERAL_FACTORS[feature]
        candidates.extend([raw / factor, raw * factor])

    if feature == 'Prealbumin':
        candidates.extend([raw / 10.0, raw * 10.0, raw * 100.0, raw / 100.0])
    elif feature in {'LDL_Cholesterol', 'HDL_Cholesterol', 'Total_Cholesterol', 'Non_HDL_Cholesterol'}:
        candidates.extend([raw / 38.61, raw * 38.61])
    elif feature == 'Triglycerides':
        candidates.extend([raw / 88.4956, raw * 88.4956])
    elif feature == 'Urine_Creatinine':
        candidates.extend([raw / 88.4, raw * 88.4, raw / 1000.0, raw * 1000.0])
    elif feature in {'Troponin_I', 'Troponin_T'}:
        candidates.extend([raw / 1000.0, raw * 1000.0])
    elif feature == 'Lactate':
        candidates.extend([raw / 9.01, raw * 9.01])
    elif feature in {'Albumin_to_Creatinine_Ratio_Urine', 'Protein_to_Creatinine_Ratio_Urine'}:
        candidates.extend([raw / 0.113, raw * 0.113])
    return unique_candidates(candidates)


def harmonize_no_conversion(feature, raw):
    bounds = NO_CONVERSION_RANGES[feature]
    if in_range(raw, bounds):
        return raw
    return None


def harmonize_conversion(feature, raw):
    bounds = CONVERSION_RANGES[feature]
    valid = [value for value in candidates_for_feature(feature, raw) if in_range(value, bounds)]
    if not valid:
        return None

    if feature == 'Prealbumin':
        preferred = [value for value in valid if 5.0 <= value <= 60.0]
        if preferred:
            valid = preferred
    elif feature in {'LDL_Cholesterol', 'HDL_Cholesterol', 'Total_Cholesterol', 'Non_HDL_Cholesterol'}:
        preferred = [value for value in valid if 20.0 <= value <= CONVERSION_RANGES[feature][1]]
        if preferred:
            valid = preferred
    elif feature == 'Triglycerides':
        preferred = [value for value in valid if 20.0 <= value <= 1000.0]
        if preferred:
            valid = preferred
    elif feature == 'Urine_Creatinine':
        preferred = [value for value in valid if 10.0 <= value <= 500.0]
        if preferred:
            valid = preferred
    elif feature in {'Troponin_I', 'Troponin_T'}:
        preferred = [value for value in valid if value < 1.0]
        if preferred:
            valid = preferred
    elif feature == 'Lactate':
        preferred = [value for value in valid if 0.3 <= value <= 15.0]
        if preferred:
            valid = preferred

    return min(valid, key=lambda value: score_candidate(feature, value))


def format_two_decimals(value):
    return f'{value:.2f}'


