            if raw is None:
                failed = True
                break
            value = harmonize_conversion(feature, raw)
            if value is None:
                failed = True
                break
            out[feature] = format_two_decimals(value)

        if not failed:
            output_rows.append(out)

    out_df = pd.DataFrame(output_rows, columns=df.columns)
    out_df.to_csv(OUTPUT, index=False)
    print(f'Wrote {len(out_df)} rows to {OUTPUT}')


if __name__ == '__main__':
